const REPO={owner:'datiancailty',name:'stock-dashboard',branch:'main'};
const DEFAULT_HOLDINGS=[{code:'600036',name:'招商银行',shares:1200,cost:31.50},{code:'000538',name:'云南白药',shares:100,cost:43.74},{code:'600795',name:'国电电力',shares:2200,cost:4.628},{code:'003816',name:'中国广核',shares:3100,cost:3.51}];
let market={stocks:[],events:[],updatedAt:null};
let newsMemory={items:[],updatedAt:null,lastScanAt:null};
let catalog=[],trackedStocks=[];
let part2Config={version:1,groups:[],extraStocks:[]};
const BOLL_SETTINGS_KEY='part2-boll-settings-v1';
let bollSettings={buyStep:.5,buyCount:4,sellStep:.5,sellCount:4,lowDev:.5,highDev:.5,yieldDev:.25};
try{bollSettings={...bollSettings,...JSON.parse(localStorage.getItem(BOLL_SETTINGS_KEY)||'{}')};}catch(error){console.warn('Part 2设置读取失败',error);}
let bollFilter='全部',bollSort='yield',bollCollapsed=new Set();
let holdings=JSON.parse(localStorage.getItem('holdings-v1')||'null')||DEFAULT_HOLDINGS;
let overrides=JSON.parse(localStorage.getItem('dividend-overrides-v1')||'{}');
let authVault=null,selectedCandidate=null;
let viewMonth=new Date(),selectedDate=new Date().toISOString().slice(0,10);
let portfolioImported=false;
const TRADE_RECORDS_KEY='strategy-trade-records-v1';
let localTradeRecords=[];
try{const savedTradeRecords=JSON.parse(localStorage.getItem(TRADE_RECORDS_KEY)||'[]');localTradeRecords=Array.isArray(savedTradeRecords)?savedTradeRecords:[];}catch(error){console.warn('旧版本地操作记录读取失败',error);}
let tradeRecords=[],strategyAnalysis={status:'waiting',learnedRules:[],advice:[]};
let strategyFeedback=[];
