$('#tradeRecordForm').onsubmit=async e=>{e.preventDefault();const code=$('#tradeStock').value,holding=holdings.find(h=>h.code===code),s=stock(code),price=Number($('#tradePrice').value),shares=Number($('#tradeShares').value),action=$('#tradeAction').value,dateValue=$('#tradeDate').value;if(!holding||!dateValue||!Number.isFinite(price)||price<=0||!Number.isInteger(shares)||shares<=0)return showMessage('记录未保存','请检查日期、股票、成交价格和成交股数。');const record={id:crypto.randomUUID?.()||`${Date.now()}-${Math.random()}`,date:dateValue,code,name:holding.name,action,price,shares,dividendPerShare:s.totalDividend,createdAt:new Date().toISOString(),context:{status:'pending',requestedDate:dateValue}};const submit=$('#tradeRecordForm button[type="submit"]');try{submit.disabled=true;submit.textContent='正在写入GitHub…';await mutateTradeRecords(records=>[record,...records.filter(r=>r.id!==record.id)],'strategy: add trade record');$('#tradeRecordDialog').close();renderStrategy();showMessage('操作已存入GitHub',`${holding.name} ${action} ${shares}股已云端保存。GitHub Actions将查询 ${dateValue} 当日的日、周、月位置，并由GPT-5.6 SOL更新策略画像。`);}catch(error){showMessage('记录未保存',error.message);}finally{submit.disabled=false;submit.textContent='保存操作';}};
