const bytesToBase64=bytes=>{let out='';for(let i=0;i<bytes.length;i+=0x8000)out+=String.fromCharCode(...bytes.subarray(i,i+0x8000));return btoa(out);};
const base64ToBytes=value=>Uint8Array.from(atob(value.replace(/\s/g,'')),c=>c.charCodeAt(0));
const decodeGithubContent=content=>new TextDecoder().decode(base64ToBytes(content));
async function sha256Hex(text){const hash=await crypto.subtle.digest('SHA-256',new TextEncoder().encode(text));return [...new Uint8Array(hash)].map(x=>x.toString(16).padStart(2,'0')).join('');}
