function openAuthDb(){return new Promise((resolve,reject)=>{const request=indexedDB.open(AUTH_DB_NAME,1);request.onupgradeneeded=()=>request.result.createObjectStore(AUTH_DB_STORE);request.onsuccess=()=>resolve(request.result);request.onerror=()=>reject(request.error);});}
async function deviceKey(create=false){const db=await openAuthDb();try{const stored=await new Promise((resolve,reject)=>{const request=db.transaction(AUTH_DB_STORE).objectStore(AUTH_DB_STORE).get(AUTH_DEVICE_KEY);request.onsuccess=()=>resolve(request.result||null);request.onerror=()=>reject(request.error);});if(stored||!create)return stored;const key=await crypto.subtle.generateKey({name:'AES-GCM',length:256},false,['encrypt','decrypt']);await new Promise((resolve,reject)=>{const transaction=db.transaction(AUTH_DB_STORE,'readwrite');transaction.objectStore(AUTH_DB_STORE).put(key,AUTH_DEVICE_KEY);transaction.oncomplete=resolve;transaction.onerror=()=>reject(transaction.error);});return key;}finally{db.close();}}
async function rememberAuth(vault){const key=await deviceKey(true),iv=crypto.getRandomValues(new Uint8Array(12)),expiresAt=Date.now()+AUTH_SESSION_TTL,clear=new TextEncoder().encode(JSON.stringify({vault,expiresAt})),ciphertext=await crypto.subtle.encrypt({name:'AES-GCM',iv},key,clear);localStorage.setItem(AUTH_SESSION_KEY,JSON.stringify({version:1,expiresAt,iv:bytesToBase64(iv),ciphertext:bytesToBase64(new Uint8Array(ciphertext))}));}
async function clearRememberedAuth(removeDeviceKey=false){localStorage.removeItem(AUTH_SESSION_KEY);if(!removeDeviceKey)return;try{const db=await openAuthDb();await new Promise((resolve,reject)=>{const transaction=db.transaction(AUTH_DB_STORE,'readwrite');transaction.objectStore(AUTH_DB_STORE).delete(AUTH_DEVICE_KEY);transaction.oncomplete=resolve;transaction.onerror=()=>reject(transaction.error);});db.close();}catch(error){console.warn('清除浏览器登录密钥失败',error);}}
async function restoreRememberedAuth(){try{const session=JSON.parse(localStorage.getItem(AUTH_SESSION_KEY)||'null');if(!session||session.version!==1||!Number.isFinite(session.expiresAt)||session.expiresAt<=Date.now())throw new Error('expired');const key=await deviceKey(false);if(!key)throw new Error('missing device key');const clear=await crypto.subtle.decrypt({name:'AES-GCM',iv:base64ToBytes(session.iv)},key,base64ToBytes(session.ciphertext)),saved=JSON.parse(new TextDecoder().decode(clear));if(saved.expiresAt!==session.expiresAt||saved.expiresAt<=Date.now()||!saved.vault?.token||saved.vault.owner!==REPO.owner||saved.vault.repo!==REPO.name)throw new Error('invalid session');authVault=saved.vault;return true;}catch(error){authVault=null;await clearRememberedAuth(false);return false;}}
function openLogin(){$('#loginError').textContent='';$('#loginDialog').showModal();}
$('#loginButton').onclick=async()=>{if(authVault){authVault=null;await clearRememberedAuth(true);updateAuthUI();}else openLogin();};
$('#loginForm').onsubmit=async e=>{e.preventDefault();$('#loginError').textContent='正在验证…';try{const config=await fetch('data/auth-config.json',{cache:'no-store'}).then(r=>{if(!r.ok)throw new Error('管理员登录尚未完成配置');return r.json();});const username=$('#loginUsername').value.trim().toLowerCase();if(await sha256Hex(username)!==config.usernameHash)throw new Error('用户名或密码错误');const vault=await decryptVault(config,$('#loginPassword').value);if(!vault.token||vault.owner!==REPO.owner||vault.repo!==REPO.name)throw new Error('登录配置无效');await rememberAuth(vault);authVault=vault;$('#loginPassword').value='';$('#loginDialog').close();updateAuthUI();await refreshStrategyCloud();}catch(error){authVault=null;await clearRememberedAuth(false);$('#loginError').textContent=error.name==='OperationError'?'用户名或密码错误':error.message;}};
function updateAuthUI(){$('#authStatus').textContent=authVault?'管理员已登录':'未登录';$('#authStatus').classList.toggle('logged',!!authVault);$('#loginButton').textContent=authVault?'退出登录':'管理员登录';document.body.classList.toggle('authenticated',!!authVault);}
async function requireAuth(){if(authVault)return authVault;openLogin();throw new Error('请先使用管理员用户名和密码登录');}
async function githubRequest(path,options={}){const response=await fetch(`https://api.github.com/repos/${REPO.owner}/${REPO.name}/contents/${path}`,{...options,headers:{Accept:'application/vnd.github+json','X-GitHub-Api-Version':'2022-11-28',Authorization:`Bearer ${authVault.token}`,'Content-Type':'application/json',...(options.headers||{})}});if(response.status===404&&options.allow404)return null;if(!response.ok){const body=await response.json().catch(()=>({}));throw new Error(body.message||`GitHub请求失败（${response.status}）`);}return response.json();}
async function mutateFile(path,mutator,message){for(let attempt=0;attempt<3;attempt++){const meta=await githubRequest(`${path}?ref=${REPO.branch}`,{allow404:true});const current=meta?JSON.parse(decodeGithubContent(meta.content)):null;const next=await mutator(current);const body={message,content:bytesToBase64(new TextEncoder().encode(JSON.stringify(next,null,2)+'\n')),branch:REPO.branch};if(meta)body.sha=meta.sha;try{return await githubRequest(path,{method:'PUT',body:JSON.stringify(body)});}catch(error){if(attempt===2||!/409|sha|conflict/i.test(error.message))throw error;}}}
async function mutateTrackedStocks(mutator){await mutateFile('data/stocks.json',current=>mutator(Array.isArray(current)?current:[]),'dashboard: update tracked stocks');}
async function mutatePart2Config(mutator){let saved=null;await mutateFile('data/part2-config.json',current=>{const base=current&&typeof current==='object'?current:{version:1,groups:[],extraStocks:[]};saved=mutator(base);return saved;},'dashboard: update Part 2 groups');part2Config=saved;return saved;}
const wait=ms=>new Promise(resolve=>setTimeout(resolve,ms));
$('#refreshMarket').onclick=async()=>{const button=$('#refreshMarket'),previous=market.updatedAt;try{await requireAuth();button.disabled=true;button.textContent='正在提交…';await mutateFile('data/market-refresh-request.json',()=>({requestedAt:new Date().toISOString(),nonce:crypto.randomUUID()}),'dashboard: request market refresh');button.textContent='正在查询行情…';$('#updateText').textContent='已提交手动查询，正在等待东方财富数据…';for(let attempt=0;attempt<30;attempt++){await wait(attempt?8000:4000);const latest=await fetchLive('market.json','data/market.json');if(latest?.updatedAt&&latest.updatedAt!==previous){market=latest;render();showMessage('行情刷新成功',`已更新 ${market.stocks.length} 只自选股的当前价格、正式分红与股息率。`);return;}}throw new Error('刷新请求已提交，但暂未等到新数据。自动更新仍会继续，请稍后再打开网页查看。');}catch(error){showMessage('手动刷新提示',error.message);}finally{button.disabled=false;button.textContent='↻ 手动刷新行情';}};
$('#refreshNews').onclick=async()=>{try{await requireAuth();await mutateFile('data/news-refresh-request.json',()=>({requestedAt:new Date().toISOString(),nonce:crypto.randomUUID()}),'dashboard: request news refresh');showMessage('刷新请求已提交','GitHub Actions 正在增量检查新公告。已记住的旧公告不会重复分析，通常几分钟后更新。');}catch(error){showMessage('提交失败',error.message);}};

async function fetchLive(filename,fallback){try{const headers={Accept:'application/vnd.github+json'};if(authVault?.token)headers.Authorization=`Bearer ${authVault.token}`;const response=await fetch(`https://api.github.com/repos/${REPO.owner}/${REPO.name}/contents/${filename}?ref=live&t=${Date.now()}`,{headers});if(response.ok){const meta=await response.json();return JSON.parse(decodeGithubContent(meta.content));}}catch(error){console.warn(error);}try{const response=await fetch(`${fallback}?t=${Date.now()}`);if(response.ok)return response.json();}catch(error){console.warn(error);}return null;}
async function loadTrackedStocks(){const response=await fetch(`data/stocks.json?t=${Date.now()}`);return response.ok?response.json():[];}
async function loadPart2Config(){const response=await fetch(`data/part2-config.json?t=${Date.now()}`);return response.ok?response.json():{version:1,groups:[],extraStocks:[]};}
function syncHoldingsWithCloud(){const local=new Map(holdings.map(item=>[item.code,item]));holdings=trackedStocks.map(item=>local.get(item.code)||{...item,shares:0,cost:0});save();}
async function load(){importPortfolioFromHash();await restoreRememberedAuth();const [marketData,newsData,stocksData,catalogData,tradePayload,strategyData,part2Data,feedbackPayload]=await Promise.all([fetchLive('market.json','data/market.json'),fetchLive('news-memory.json','data/news-memory.json'),loadTrackedStocks(),fetch('data/stock-catalog.json').then(r=>r.ok?r.json():[]).catch(()=>[]),loadCloudTradeRecords(),fetchLive('strategy-analysis.json','data/strategy-analysis.json'),loadPart2Config(),loadStrategyFeedback()]);if(marketData)market=marketData;if(newsData)newsMemory=newsData;if(strategyData)strategyAnalysis=strategyData;if(part2Data)part2Config=part2Data;tradeRecords=tradePayload.records;strategyFeedback=feedbackPayload.records;trackedStocks=stocksData;catalog=catalogData;syncHoldingsWithCloud();updateAuthUI();render();if(portfolioImported)showMessage('持仓导入成功',`已将 ${holdings.length} 只A股的持仓和成本保存到当前浏览器。江农发债属于可转债，未导入A股面板。`);}
load();
